const { google } = require('googleapis');
const path = require('path');
require('dotenv').config();

// Initialize Google Sheets API
const auth = new google.auth.GoogleAuth({
  keyFile: process.env.GOOGLE_SERVICE_ACCOUNT_PATH || path.join(__dirname, '../google-service-account.json'),
    scopes: ['https://www.googleapis.com/auth/spreadsheets'],
    });

    const sheets = google.sheets({ version: 'v4', auth });

    // Spreadsheet IDs from environment variables
    const SPREADSHEET_IDS = {
      products: process.env.GOOGLE_SHEET_ID_PRODUCTS,
        credentials: process.env.GOOGLE_SHEET_ID_CREDENTIALS,
          logs: process.env.GOOGLE_SHEET_ID_LOGS,
          };

          // Helper: Convert row data to object
          function rowToObject(headers, row) {
            const obj = {};
              headers.forEach((header, index) => {
                  obj[header] = row[index] || '';
                    });
                      return obj;
                      }

                      // Helper: Convert object to row data
                      function objectToRow(headers, obj) {
                        return headers.map(header => obj[header] || '');
                        }

                        // ============================================
                        // PRODUCTS OPERATIONS
                        // ============================================

                        /**
                         * Read all products from a specific sheet
                          * @param {string} sheetName - Name of the sheet (e.g., 'All Products', 'Club Jerseys')
                           * @returns {Array} Array of product objects
                            */
                            async function readProducts(sheetName = 'Sheet1') {
                              try {
                                  const response = await sheets.spreadsheets.values.get({
                                        spreadsheetId: SPREADSHEET_IDS.products,
                                              range: `${sheetName}!A:O`, // A to O columns (15 columns)
                                                  });

                                                      const rows = response.data.values;
                                                          if (!rows || rows.length === 0) {
                                                                return [];
                                                                    }

                                                                        const headers = rows[0]; // First row is headers
                                                                            const dataRows = rows.slice(1); // Rest are data

                                                                                return dataRows.map(row => rowToObject(headers, row));
                                                                                  } catch (error) {
                                                                                      console.error('Error reading products:', error);
                                                                                          throw error;
                                                                                            }
                                                                                            }

                                                                                            /**
                                                                                             * Write a new product to sheet
                                                                                              * @param {string} sheetName - Name of the sheet
                                                                                               * @param {Object} product - Product object
                                                                                                */
                                                                                                async function writeProduct(sheetName, product) {
                                                                                                  try {
                                                                                                      // Get headers first
                                                                                                          const headerResponse = await sheets.spreadsheets.values.get({
                                                                                                                spreadsheetId: SPREADSHEET_IDS.products,
                                                                                                                      range: `${sheetName}!A1:O1`,
                                                                                                                          });

                                                                                                                              const headers = headerResponse.data.values?.[0] || [
                                                                                                                                    'id', 'name', 'price', 'category', 'image1', 'image2', 
                                                                                                                                          'description', 'customisable', 'sizes', 'label', 'status',
                                                                                                                                                'created_at', 'created_by', 'last_modified_at', 'last_modified_by'
                                                                                                                                                    ];

                                                                                                                                                        const row = objectToRow(headers, product);

                                                                                                                                                            await sheets.spreadsheets.values.append({
                                                                                                                                                                  spreadsheetId: SPREADSHEET_IDS.products,
                                                                                                                                                                        range: `${sheetName}!A:O`,
                                                                                                                                                                              valueInputOption: 'RAW',
                                                                                                                                                                                    resource: {
                                                                                                                                                                                            values: [row],
                                                                                                                                                                                                  },
                                                                                                                                                                                                      });

                                                                                                                                                                                                          return true;
                                                                                                                                                                                                            } catch (error) {
                                                                                                                                                                                                                console.error('Error writing product:', error);
                                                                                                                                                                                                                    throw error;
                                                                                                                                                                                                                      }
                                                                                                                                                                                                                      }

                                                                                                                                                                                                                      /**
                                                                                                                                                                                                                       * Update an existing product
                                                                                                                                                                                                                        * @param {string} sheetName - Name of the sheet
                                                                                                                                                                                                                         * @param {string} productId - Product ID to update
                                                                                                                                                                                                                          * @param {Object} updates - Updated product data
                                                                                                                                                                                                                           */
                                                                                                                                                                                                                           async function updateProduct(sheetName, productId, updates) {
                                                                                                                                                                                                                             try {
                                                                                                                                                                                                                                 // Find the row with this product ID
                                                                                                                                                                                                                                     const products = await readProducts(sheetName);
                                                                                                                                                                                                                                         const rowIndex = products.findIndex(p => p.id === productId);

                                                                                                                                                                                                                                             if (rowIndex === -1) {
                                                                                                                                                                                                                                                   throw new Error(`Product ${productId} not found in ${sheetName}`);
                                                                                                                                                                                                                                                       }

                                                                                                                                                                                                                                                           // Row number in sheet (add 2: 1 for header, 1 for 0-index)
                                                                                                                                                                                                                                                               const sheetRow = rowIndex + 2;

                                                                                                                                                                                                                                                                   // Get headers
                                                                                                                                                                                                                                                                       const headerResponse = await sheets.spreadsheets.values.get({
                                                                                                                                                                                                                                                                             spreadsheetId: SPREADSHEET_IDS.products,
                                                                                                                                                                                                                                                                                   range: `${sheetName}!A1:O1`,
                                                                                                                                                                                                                                                                                       });
                                                                                                                                                                                                                                                                                           const headers = headerResponse.data.values[0];

                                                                                                                                                                                                                                                                                               // Merge existing data with updates
                                                                                                                                                                                                                                                                                                   const updatedProduct = { ...products[rowIndex], ...updates };
                                                                                                                                                                                                                                                                                                       const row = objectToRow(headers, updatedProduct);

                                                                                                                                                                                                                                                                                                           await sheets.spreadsheets.values.update({
                                                                                                                                                                                                                                                                                                                 spreadsheetId: SPREADSHEET_IDS.products,
                                                                                                                                                                                                                                                                                                                       range: `${sheetName}!A${sheetRow}:O${sheetRow}`,
                                                                                                                                                                                                                                                                                                                             valueInputOption: 'RAW',
                                                                                                                                                                                                                                                                                                                                   resource: {
                                                                                                                                                                                                                                                                                                                                           values: [row],
                                                                                                                                                                                                                                                                                                                                                 },
                                                                                                                                                                                                                                                                                                                                                     });

                                                                                                                                                                                                                                                                                                                                                         return true;
                                                                                                                                                                                                                                                                                                                                                           } catch (error) {
                                                                                                                                                                                                                                                                                                                                                               console.error('Error updating product:', error);
                                                                                                                                                                                                                                                                                                                                                                   throw error;
                                                                                                                                                                                                                                                                                                                                                                     }
                                                                                                                                                                                                                                                                                                                                                                     }

                                                                                                                                                                                                                                                                                                                                                                     /**
                                                                                                                                                                                                                                                                                                                                                                      * Soft delete a product (mark as DELETION_PENDING)
                                                                                                                                                                                                                                                                                                                                                                       * @param {string} sheetName - Name of the sheet
                                                                                                                                                                                                                                                                                                                                                                        * @param {string} productId - Product ID
                                                                                                                                                                                                                                                                                                                                                                         * @param {string} adminId - Who requested the delete
                                                                                                                                                                                                                                                                                                                                                                          */
                                                                                                                                                                                                                                                                                                                                                                          async function softDeleteProduct(sheetName, productId, adminId) {
                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                await updateProduct(sheetName, productId, {
                                                                                                                                                                                                                                                                                                                                                                                      status: 'DELETION_PENDING',
                                                                                                                                                                                                                                                                                                                                                                                            last_modified_by: adminId,
                                                                                                                                                                                                                                                                                                                                                                                                  last_modified_at: new Date().toISOString(),
                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                          return true;
                                                                                                                                                                                                                                                                                                                                                                                                            } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                console.error('Error soft deleting product:', error);
                                                                                                                                                                                                                                                                                                                                                                                                                    throw error;
                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                                                                                                                                                                      /**
                                                                                                                                                                                                                                                                                                                                                                                                                       * Permanently delete a product (owner approved)
                                                                                                                                                                                                                                                                                                                                                                                                                        * @param {string} sheetName - Name of the sheet
                                                                                                                                                                                                                                                                                                                                                                                                                         * @param {string} productId - Product ID
                                                                                                                                                                                                                                                                                                                                                                                                                          */
                                                                                                                                                                                                                                                                                                                                                                                                                          async function permanentDeleteProduct(sheetName, productId) {
                                                                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                                                                const products = await readProducts(sheetName);
                                                                                                                                                                                                                                                                                                                                                                                                                                    const rowIndex = products.findIndex(p => p.id === productId);

                                                                                                                                                                                                                                                                                                                                                                                                                                        if (rowIndex === -1) {
                                                                                                                                                                                                                                                                                                                                                                                                                                              throw new Error(`Product ${productId} not found`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                      const sheetRow = rowIndex + 2; // Account for header + 0-index

                                                                                                                                                                                                                                                                                                                                                                                                                                                          await sheets.spreadsheets.batchUpdate({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                spreadsheetId: SPREADSHEET_IDS.products,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      resource: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              requests: [{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        deleteDimension: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    range: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  sheetId: 0, // Assumes first sheet, may need to get actual sheet ID
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                dimension: 'ROWS',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              startIndex: sheetRow - 1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            endIndex: sheetRow,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.error('Error permanently deleting product:', error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  throw error;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // ============================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // CREDENTIALS OPERATIONS
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // ============================================

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    /**
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     * Read all credentials
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      * @returns {Array} Array of credential objects
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       async function readCredentials() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             const response = await sheets.spreadsheets.values.get({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   spreadsheetId: SPREADSHEET_IDS.credentials,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         range: 'Sheet1!A:G',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 const rows = response.data.values;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     if (!rows || rows.length === 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           return [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   const headers = rows[0];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       const dataRows = rows.slice(1);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           return dataRows.map(row => rowToObject(headers, row));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 console.error('Error reading credentials:', error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     throw error;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       /**
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        * Write a new credential (add admin)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         * @param {Object} credential - Credential object
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          async function writeCredential(credential) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const headerResponse = await sheets.spreadsheets.values.get({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      spreadsheetId: SPREADSHEET_IDS.credentials,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            range: 'Sheet1!A1:G1',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const headers = headerResponse.data.values?.[0] || [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          'username', 'password', 'name', 'role', 'status', 'created_at', 'created_by'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const row = objectToRow(headers, credential);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await sheets.spreadsheets.values.append({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            spreadsheetId: SPREADSHEET_IDS.credentials,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  range: 'Sheet1!A:G',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        valueInputOption: 'RAW',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              resource: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      values: [row],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          console.error('Error writing credential:', error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              throw error;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ============================================
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // LOGGING OPERATIONS
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ============================================

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                /**
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 * Write log entry to appropriate sheet
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  * @param {string} sheetName - 'Authentication', 'Product Actions', or 'Owner Actions'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   * @param {Object} logEntry - Log data
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    */
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    async function writeLog(sheetName, logEntry) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Get headers for the specific log sheet
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const headerResponse = await sheets.spreadsheets.values.get({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    spreadsheetId: SPREADSHEET_IDS.logs,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          range: `${sheetName}!A1:F1`, // Adjust range based on sheet
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const headers = headerResponse.data.values?.[0];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (!headers) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            throw new Error(`No headers found in ${sheetName}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const row = objectToRow(headers, logEntry);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await sheets.spreadsheets.values.append({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              spreadsheetId: SPREADSHEET_IDS.logs,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    range: `${sheetName}!A:F`,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          valueInputOption: 'RAW',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                resource: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        values: [row],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return true;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.error(`Error writing log to ${sheetName}:`, error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                throw error;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
/**
 * Read logs from a specific log sheet
 * @param {string} sheetName - 'Authentication', 'Product Actions', or 'Owner Actions'
 * @returns {Array} Array of log objects
 */
async function readLogs(sheetName) {
  try {
    console.log(`Reading logs from: ${sheetName}`);
    console.log(`Spreadsheet ID: ${SPREADSHEET_IDS.logs}`);
    
    const response = await sheets.spreadsheets.values.get({
      spreadsheetId: SPREADSHEET_IDS.logs,
      range: `${sheetName}!A:Z`, // Expand range to Z to be safe
    });

    const rows = response.data.values;
    
    console.log(`Rows received: ${rows ? rows.length : 0}`);
    
    if (!rows || rows.length === 0) {
      console.log('No data found in logs sheet');
      return [];
    }

    if (rows.length === 1) {
      console.log('Only headers found, no data rows');
      return [];
    }

    const headers = rows[0];
    const dataRows = rows.slice(1);

    console.log(`Headers: ${headers.join(', ')}`);
    console.log(`Data rows: ${dataRows.length}`);

    const logs = dataRows.map(row => rowToObject(headers, row));
    
    return logs;
  } catch (error) {
    console.error('Error reading logs:', error.message);
    console.error('Full error:', error);
    throw error;
  }
}

/**
 * Update entire row in a sheet
 * @param {string} sheetName - Sheet name
 * @param {number} rowNumber - Row number (1-based, includes header)
 * @param {Array} rowData - Array of values for the row
 * @param {string} spreadsheetId - Optional spreadsheet ID (uses env default if not provided)
 */
async function updateRow(sheetName, rowNumber, rowData, spreadsheetId = null) {
  try {
    const auth = await authorize();
    const sheets = google.sheets({ version: 'v4', auth });
    
    const targetSpreadsheetId = spreadsheetId || process.env.SPREADSHEET_ID;
    
    // Convert row data to range (e.g., row 2 → A2:O2 for 15 columns)
    const lastColumn = String.fromCharCode(65 + rowData.length - 1); // A=65, B=66, etc.
    const range = `${sheetName}!A${rowNumber}:${lastColumn}${rowNumber}`;
    
    await sheets.spreadsheets.values.update({
      spreadsheetId: targetSpreadsheetId,
      range,
      valueInputOption: 'RAW',
      resource: {
        values: [rowData]
      }
    });
    
    console.log(`✅ Updated row ${rowNumber} in ${sheetName}`);
    
  } catch (error) {
    console.error('Error updating row:', error);
    throw error;
  }
}

/**
 * Update single cell in a sheet
 * @param {string} sheetName - Sheet name
 * @param {number} rowNumber - Row number (1-based)
 * @param {number} columnNumber - Column number (1-based, A=1, B=2, etc.)
 * @param {any} value - Value to set
 * @param {string} spreadsheetId - Optional spreadsheet ID
 */
async function updateCell(sheetName, rowNumber, columnNumber, value, spreadsheetId = null) {
  try {
    const auth = await authorize();
    const sheets = google.sheets({ version: 'v4', auth });
    
    const targetSpreadsheetId = spreadsheetId || process.env.SPREADSHEET_ID;
    
    // Convert column number to letter (1=A, 2=B, etc.)
    const columnLetter = String.fromCharCode(64 + columnNumber);
    const range = `${sheetName}!${columnLetter}${rowNumber}`;
    
    await sheets.spreadsheets.values.update({
      spreadsheetId: targetSpreadsheetId,
      range,
      valueInputOption: 'RAW',
      resource: {
        values: [[value]]
      }
    });
    
    console.log(`✅ Updated cell ${range} to: ${value}`);
    
  } catch (error) {
    console.error('Error updating cell:', error);
    throw error;
  }
}

/**
 * Delete row from sheet
 * @param {string} sheetName - Sheet name
 * @param {number} rowNumber - Row number to delete (1-based)
 * @param {string} spreadsheetId - Optional spreadsheet ID
 */
async function deleteRow(sheetName, rowNumber, spreadsheetId = null) {
  try {
    const auth = await authorize();
    const sheets = google.sheets({ version: 'v4', auth });
    
    const targetSpreadsheetId = spreadsheetId || process.env.SPREADSHEET_ID;
    
    // Get sheet ID by name
    const spreadsheet = await sheets.spreadsheets.get({
      spreadsheetId: targetSpreadsheetId
    });
    
    const sheet = spreadsheet.data.sheets.find(s => s.properties.title === sheetName);
    if (!sheet) {
      throw new Error(`Sheet not found: ${sheetName}`);
    }
    
    const sheetId = sheet.properties.sheetId;
    
    // Delete the row (0-based index for API)
    await sheets.spreadsheets.batchUpdate({
      spreadsheetId: targetSpreadsheetId,
      resource: {
        requests: [
          {
            deleteDimension: {
              range: {
                sheetId: sheetId,
                dimension: 'ROWS',
                startIndex: rowNumber - 1,
                endIndex: rowNumber
              }
            }
          }
        ]
      }
    });
    
    console.log(`✅ Deleted row ${rowNumber} from ${sheetName}`);
    
  } catch (error) {
    console.error('Error deleting row:', error);
    throw error;
  }
}



